import React, { useState } from 'react';
import axios from 'axios';

const AdminDashboard: React.FC = () => {
    const [personId, setPersonId] = useState('');
    const [person, setPerson] = useState(null);
    const [metrics, setMetrics] = useState(null);

    const fetchPerson = async () => {
        try {
            const response = await axios.get(`/api/persons/${personId}`);
            setPerson(response.data);
        } catch (error) {
            console.error('Failed to fetch person');
        }
    };

    const deletePerson = async () => {
        try {
            await axios.delete(`/api/persons/${personId}`);
            setPerson(null);
        } catch (error) {
            console.error('Failed to delete person');
        }
    };

    const fetchMetrics = async () => {
        try {
            const response = await axios.get('/api/metrics');
            setMetrics(response.data);
        } catch (error) {
            console.error('Failed to fetch metrics');
        }
    };

    return (
        <div>
            <h2>Admin Dashboard</h2>
            <div>
                <input
                    type="text"
                    placeholder="Person ID"
                    value={personId}
                    onChange={(e) => setPersonId(e.target.value)}
                />
                <button onClick={fetchPerson}>Get Person</button>
                <button onClick={deletePerson}>Delete Person</button>
            </div>
            {person && (
                <div>
                    <h3>Person Details</h3>
                    <p>ID: {person.person_id}</p>
                    <p>Name: {person.name}</p>
                    <p>Embeddings: {person.embeddings.length}</p>
                </div>
            )}
            <button onClick={fetchMetrics}>Get Metrics</button>
            {metrics && (
                <div>
                    <h3>Metrics</h3>
                    <p>Recognitions: {metrics.recognition_count}</p>
                    <p>Enrolls: {metrics.enroll_count}</p>
                    <p>Avg Latency: {metrics.avg_latency_ms} ms</p>
                </div>
            )}
        </div>
    );
};

export default AdminDashboard;
